code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Checkbox, icon } from 'decantr/components';

code.example:
function ChecklistCard({ title, items }) {
  const { div, h3, span } = tags;

  return Card({},
    Card.Header({},
      div({ class: css('_flex _aic _jcsb') },
        h3({ class: css('_heading5') }, icon('list'), ` ${title}`),
        span({ class: css('_textsm _fgmuted') }, `${items.length} items`)
      )
    ),
    Card.Body({ class: css('_flex _col _gap2') },
      ...items.map(item =>
        Checkbox({ label: typeof item === 'string' ? item : `${item.quantity} ${item.unit} ${item.name}${item.preparation ? ' — ' + item.preparation : ''}` })
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Badge, Card, Checkbox, icon } from 'decantr/components';

code.example:
function OnboardingChecklist({ steps }) {
  const { div, span, h3, p } = tags;
  const completed = steps.filter(s => s.done).length;
  const pct = Math.round((completed / steps.length) * 100);

  return Card({},
    Card.Header({},
      div({ class: css('_flex _aic _jcsb') },
        h3({ class: css('_heading5') }, 'Getting Started'),
        Badge({ variant: pct === 100 ? 'success' : 'primary' }, `${pct}%`)
      ),
      div({ class: css('_mt2 _h[4px] _bgmuted/20 _rfull _overflow[hidden]') },
        div({ class: css(`_h[4px] _bgprimary _rfull _w[${pct}%]`) })
      )
    ),
    Card.Body({ class: css('_flex _col _gap1') },
      ...steps.map((step, i) =>
        div({ class: css('_flex _gap3 _aic _p3 _borderB') },
          Checkbox({ checked: step.done }),
          div({ class: css('_flex _col _flex1') },
            span({ class: css(`_textsm ${step.done ? '_fgmuted _lineThrough' : '_bold'}`) }, `${i + 1}. ${step.title}`),
            p({ class: css('_textxs _fgmuted') }, step.description)
          ),
          step.done ? icon('check-circle', { class: css('_fgsuccess') }) : null
        )
      )
    )
  );
}

